#include "../main.h"

__kernel void kernel_gpu_opencl(par_str par,
                                dim_str dim,
                                __global box_str *box,
                                __global FOUR_VECTOR *rv,
                                __global fp *qv,
                                __global FOUR_VECTOR *fv)
{
    int i = (int)get_local_id(0);
    int l = (int)get_group_id(0);

    if (l >= dim.number_boxes || i >= NUMBER_PAR_PER_BOX) {
        return;
    }

    fp alpha = par.alpha;
    fp a2 = (fp)2.0f * alpha * alpha;

    long first_i = box[l].offset;
    __global FOUR_VECTOR *rA = &rv[first_i];
    __global FOUR_VECTOR *fA = &fv[first_i];

    fp f_v = fA[i].v;
    fp f_x = fA[i].x;
    fp f_y = fA[i].y;
    fp f_z = fA[i].z;

    for (int k = 0; k < (1 + box[l].nn); k++) {
        int pointer = (k == 0) ? l : box[l].nei[k - 1].number;

        long first_j = box[pointer].offset;
        __global FOUR_VECTOR *rB = &rv[first_j];
        __global fp *qB = &qv[first_j];

        for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
            fp r2 = rA[i].v + rB[j].v - DOT(rA[i], rB[j]);
            fp u2 = a2 * r2;
            fp vij = exp(-u2);
            fp fs = (fp)2.0f * vij;

            fp dx = rA[i].x - rB[j].x;
            fp dy = rA[i].y - rB[j].y;
            fp dz = rA[i].z - rB[j].z;

            fp fxij = fs * dx;
            fp fyij = fs * dy;
            fp fzij = fs * dz;

            fp q = qB[j];
            f_v += q * vij;
            f_x += q * fxij;
            f_y += q * fyij;
            f_z += q * fzij;
        }
    }

    fA[i].v = f_v;
    fA[i].x = f_x;
    fA[i].y = f_y;
    fA[i].z = f_z;
}
